 {"id":"asupersync-c61","title":"[Runtime] Implement Runtime Configuration and Builder","description":"# Runtime Configuration

## Overview
Configurable runtime builder with sensible defaults and tuning options.

## RuntimeConfig

```rust
pub struct RuntimeConfig {
    /// Number of worker threads (default: num_cpus)
    pub worker_threads: usize,

    /// Stack size per worker thread (default: 2MB)
    pub thread_stack_size: usize,

    /// Name prefix for worker threads
    pub thread_name_prefix: String,

    /// Global queue size limit (0 = unbounded)
    pub global_queue_limit: usize,

    /// Work stealing batch size
    pub steal_batch_size: usize,

    /// Blocking pool configuration
    pub blocking: BlockingPoolConfig,

    /// Enable parking lot for idle workers
    pub enable_parking: bool,

    /// Time slice for cooperative yielding (polls)
    pub poll_budget: u32,

    /// Callbacks
    pub on_thread_start: Option<Arc<dyn Fn() + Send + Sync>>,
    pub on_thread_stop: Option<Arc<dyn Fn() + Send + Sync>>,
}

impl Default for RuntimeConfig {
    fn default() -> Self {
        Self {
            worker_threads: num_cpus::get(),
            thread_stack_size: 2 * 1024 * 1024,
            thread_name_prefix: "asupersync-worker".to_string(),
            global_queue_limit: 0,
            steal_batch_size: 16,
            blocking: BlockingPoolConfig::default(),
            enable_parking: true,
            poll_budget: 128,
            on_thread_start: None,
            on_thread_stop: None,
        }
    }
}
```

## RuntimeBuilder

```rust
pub struct RuntimeBuilder {
    config: RuntimeConfig,
}

impl RuntimeBuilder {
    pub fn new() -> Self {
        Self { config: RuntimeConfig::default() }
    }

    pub fn worker_threads(mut self, n: usize) -> Self {
        self.config.worker_threads = n;
        self
    }

    pub fn thread_stack_size(mut self, size: usize) -> Self {
        self.config.thread_stack_size = size;
        self
    }

    pub fn thread_name(mut self, prefix: impl Into<String>) -> Self {
        self.config.thread_name_prefix = prefix.into();
        self
    }

    pub fn blocking_threads(mut self, min: usize, max: usize) -> Self {
        self.config.blocking.min_threads = min;
        self.config.blocking.max_threads = max;
        self
    }

    pub fn on_thread_start<F>(mut self, f: F) -> Self
    where
        F: Fn() + Send + Sync + 'static,
    {
        self.config.on_thread_start = Some(Arc::new(f));
        self
    }

    pub fn build(self) -> Result<Runtime, Error> {
        Runtime::with_config(self.config)
    }
}
```

## Presets

```rust
impl RuntimeBuilder {
    /// Single-threaded runtime (Phase 0 compatible)
    pub fn current_thread() -> Self {
        Self::new().worker_threads(1)
    }

    /// Multi-threaded with defaults
    pub fn multi_thread() -> Self {
        Self::new()
    }

    /// High-throughput: more workers, larger batches
    pub fn high_throughput() -> Self {
        Self::new()
            .worker_threads(num_cpus::get() * 2)
            .steal_batch_size(32)
    }

    /// Low-latency: smaller batches, aggressive stealing
    pub fn low_latency() -> Self {
        Self::new()
            .steal_batch_size(4)
            .poll_budget(32)
    }
}
```

## Runtime Entry Points

```rust
impl Runtime {
    /// Block on a future (entry point)
    pub fn block_on<F: Future>(&self, future: F) -> F::Output {
        // Enter runtime context
        // Run future to completion
        // Handle panics
    }

    /// Get handle for spawning from outside
    pub fn handle(&self) -> RuntimeHandle {
        RuntimeHandle { inner: self.inner.clone() }
    }
}

impl RuntimeHandle {
    /// Spawn from outside async context
    pub fn spawn<F>(&self, future: F) -> JoinHandle<F::Output>
    where
        F: Future + Send + 'static,
        F::Output: Send + 'static;
}
```

